```razor
@page "/courses"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>Courses - University Course Catalog</PageTitle>

<h1>Course Catalog</h1>
<p class="text-muted">Browse and search available courses for the upcoming semester.</p>

<form method="get" class="row g-3 mb-4">
    <div class="col-md-6">
        <input type="text" name="search" value="@Search" class="form-control" placeholder="Search courses by title, code, or instructor..." />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button type="submit" class="btn btn-primary w-100">Search</button>
    </div>
</form>

@if (courses.Any())
{
    <div class="table-responsive">
        <table class="table table-hover">
            <thead class="table-light">
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Instructor</th>
                    <th>Credits</th>
                    <th>Schedule</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in courses)
                {
                    <tr>
                        <td><strong>@course.Code</strong></td>
                        <td>@course.Title</td>
                        <td>@course.Department.Name</td>
                        <td>@course.Instructor.Name</td>
                        <td>@course.Credits</td>
                        <td class="small">@course.Schedule</td>
                        <td><a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
    <p class="text-muted">Showing @courses.Count course(s)</p>
}
else
{
    <div class="alert alert-info">No courses found matching your criteria. Try adjusting your search or filter.</div>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Course> courses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = Catalog.GetDepartments();
        courses = Catalog.GetCourses(Search, DepartmentId);
    }
}
```

8. **Create `/tmp/sv-d253e005ab3b4e839a0384d19f213209/UniversityCourseCatalog/Components/Pages/CourseDetail.razor`** — Course detail page:
```razor
@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

@if (course is null)
{
    <PageTitle>Course Not Found</PageTitle>
    <div class="alert alert-warning">Course not found.</div>
    <a href="/courses" class="btn btn-primary">Back to Courses</a>
}
else
{
    <PageTitle>@course.Title - University Course Catalog</PageTitle>

    <nav aria-label="breadcrumb" class="mb-3">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/courses">Courses</a></li>
            <li class="breadcrumb-item"><a href="/courses?departmentId=@course.DepartmentId">@course.Department.Name</a></li>
            <li class="breadcrumb-item active">@course.Code</li>
        </ol>
    </nav>

    <div class="row">
        <div class="col-lg-8">
            <h1>@course.Title</h1>
            <span class="badge bg-primary fs-6 mb-3">@course.Code</span>

            <h4 class="mt-4">Description</h4>
            <p>@course.Description</p>

            <h4 class="mt-4">Schedule &amp; Location</h4>
            <table class="table table-bordered w-auto">
                <tr><th>Schedule</th><td>@course.Schedule</td></tr>
                <tr><th>Room</th><td>@course.Room</td></tr>
                <tr><th>Credits</th><td>@course.Credits</td></tr>
            </table>

            <h4 class="mt-4">Enrollment</h4>
            <div class="progress mb-2" style="height: 25px;">
                @{
                    var pct = (int)((double)course.CurrentEnrollment / course.MaxEnrollment * 100);
                    var barClass = pct >= 90 ? "bg-danger" : pct >= 70 ? "bg-warning" : "bg-success";
                }
                <div class="progress-bar @barClass" style="width: @pct%">@course.CurrentEnrollment / @course.MaxEnrollment</div>
            </div>
            <p class="text-muted">@(course.MaxEnrollment - course.CurrentEnrollment) seats remaining</p>

            <a href="/enroll?courseId=@course.Id" class="btn btn-primary">Request Enrollment</a>
        </div>

        <div class="col-lg-4">
            <div class="card shadow-sm">
                <div class="card-body">
                    <h5 class="card-title">Instructor</h5>
                    <h6>@course.Instructor.Name</h6>
                    <p class="text-muted mb-2">@course.Instructor.Title</p>
                    <p>@course.Instructor.Bio</p>
                    <p class="mb-0"><strong>Email:</strong> <a href="mailto:@course.Instructor.Email">@course.Instructor.Email</a></p>
                </div>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;

    protected override void OnInitialized()
    {
        course = Catalog.GetCourse(Id);
    }
}
```

