@page "/"
@using UniversityCourseCatalog.Services
@using UniversityCourseCatalog.Models
@inject CatalogService Catalog

<PageTitle>University Course Catalog</PageTitle>

<div class="text-center mb-5">
    <h1 class="display-4 fw-bold">University Course Catalog</h1>
    <p class="lead text-muted">Explore our departments and courses for the upcoming semester</p>
    <a href="/courses" class="btn btn-primary btn-lg me-2">Browse All Courses</a>
    <a href="/enroll" class="btn btn-outline-primary btn-lg">Enroll Now</a>
</div>

<section class="mb-5">
    <h2 class="mb-3">Featured Courses</h2>
    <div class="row g-4">
        @foreach (var course in featuredCourses)
        {
            <div class="col-md-6 col-lg-4">
                <div class="card h-100 shadow-sm">
                    <div class="card-body">
                        <span class="badge bg-secondary mb-2">@course.Code</span>
                        <h5 class="card-title">@course.Title</h5>
                        <p class="card-text text-muted small">@course.Department.Name &bull; @course.Credits credits</p>
                        <p class="card-text">@course.Description[..Math.Min(100, course.Description.Length)]...</p>
                    </div>
                    <div class="card-footer bg-transparent">
                        <a href="/courses/@course.Id" class="btn btn-sm btn-outline-primary">View Details</a>
                    </div>
                </div>
            </div>
        }
    </div>
</section>

<section>
    <h2 class="mb-3">Departments</h2>
    <div class="row g-3">
        @foreach (var dept in departments)
        {
            <div class="col-md-6 col-lg-4">
                <div class="card border-start border-primary border-4">
                    <div class="card-body">
                        <h5 class="card-title">@dept.Name</h5>
                        <p class="card-text text-muted">@dept.Description</p>
                        <a href="/courses?departmentId=@dept.Id" class="stretched-link text-decoration-none">
                            Browse @dept.Code courses →
                        </a>
                    </div>
                </div>
            </div>
        }
    </div>
</section>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = Catalog.GetFeaturedCourses();
        departments = Catalog.GetDepartments();
    }
}

